settings.custom_liquid:
{% comment %}
Announcement bar with desktop + mobile variants.
- Desktop shows full message
- Mobile shows shorter message OR can be hidden

Set mobile_mode to:
- 'short' to show mobile_message
- 'hide' to hide on mobile
{% endcomment %}

{% assign desktop_message = 'Free Shipping + 30-Day Guarantee ✅' %}
{% assign mobile_message  = 'Free Shipping + 30-Day Guarantee ✅' %}
{% assign mobile_mode = 'short' %}

<style>
  .nuve-announcement{
    width: 100%;
    background: #d9cffc; /* lilac */
    color: #111;
    border-bottom: 1px solid rgba(0,0,0,.08);
    text-align: center;
    font-weight: 900;
    letter-spacing: 0.02em;
    padding: 10px 14px;
    font-size: 14px;
    line-height: 1.2;

    /* Prevent weird overflow/scroll on mobile */
    overflow: hidden;
  }

  .nuve-announcement__inner{
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 8px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .nuve-announcement__desktop{ display: inline; }
  .nuve-announcement__mobile{ display: none; }

  /* Mobile: smaller */
  @media (max-width: 749px){
    .nuve-announcement{
      padding: 7px 12px;
      font-size: 12px;
      font-weight: 800;
      letter-spacing: 0.01em;
    }
    .nuve-announcement__desktop{ display: none; }
    .nuve-announcement__mobile{ display: inline; }
  }

  /* Optional sticky (remove this class if you don't want sticky) */
  .nuve-announcement.is-sticky{
    position: sticky;
    top: 0;
    z-index: 999;
  }
</style>

<div class="nuve-announcement is-sticky">
  <div class="nuve-announcement__inner">
    <span class="nuve-announcement__desktop">{{ desktop_message }}</span>

    {% if mobile_mode == 'short' %}
      <span class="nuve-announcement__mobile">{{ mobile_message }}</span>
    {% endif %}
  </div>
</div>

{% if mobile_mode == 'hide' %}
  <style>
    @media (max-width: 749px){
      .nuve-announcement{ display:none !important; }
    }
  </style>
{% endif %}
